#include<bits/stdc++.h>
using namespace std;
struct node
{
    int a[401],len;
    node()
    {
        len=0;
        memset(a,0,sizeof(a));
    }
    node(long long x)
    {
        if(x<0)
        {
            x=-x;
        }
        len=0;
        memset(a,0,sizeof(a));
        while(x)
        {
            a[++len]=x%10;
            x/=10;
        }
    }
    void print()const
    {
        if(len<=0)
        {
            printf("0");
        }
        for(int i=len;i>=1;i--)
        {
            printf("%d",a[i]);
        }
    }
    node operator*(const node&b)const
    {
        node c;
        int l=len+b.len;
        for(int i=0;i<len;i++)
        {
            for(int j=0;j<b.len;j++)
            {
                c.a[i+j+1]+=a[i+1]*b.a[j+1];
            }
        }
        for(int i=1;i<=l+10;i++)
        {
            c.a[i+1]+=c.a[i]/10;
            c.a[i]%=10;
        }
        while(c.a[l]==0)
        {
            l--;
        }
        c.len=l;
        return c;
    }
    friend node operator^(const node&a1,const int &b1)
    {
        node a=a1;
        int b=b1;
        node ans;
        ans=1;
        while(b)
        {
            if(b%2==1)
            {
                ans=ans*a;
            }
            a=a*a;
            b/=2;
        }
        return ans;
    }
    node operator+(const node&b)const
    {
        node c;
        c.len=max(len,b.len);
        for(int i=1;i<=c.len;i++)
        {
            c.a[i]+=a[i]+b.a[i];
            c.a[i+1]+=c.a[i]/10;
            c.a[i]%=10;
        }
        if(c.a[c.len+1])
        {
            c.len++;
        }
        return c;
    }
    node operator-(const node&b2)const
    {
        node b=b2;
        node a=(*this);
        node ans=a;
        bool jie=false;
        for(int i=1;i<=a.len;i++)
        {
            if(jie)
            {
                ans.a[i]--;
                jie=false;
            }
            ans.a[i]-=b.a[i];
            if(ans.a[i]<0)
            {
                ans.a[i]+=10;
                jie=true;
            }
        }
        while(ans.a[ans.len]==0)
        {
            ans.len--;
        }
        return ans;
    }
}dp[41];
int main()
{
    int n,d;
    scanf("%d%d",&n,&d);
    node temp;
    temp=1;
    dp[0]=1;
    dp[1]=2;
    for(int i=2;i<=d;i++)
    {
        dp[i]=(dp[i-1]^n)+temp;
    }
    (dp[d]-dp[d-1]).print();
    return 0;
}
